section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "agent-drift-detection-statistical-output",
  "required": [
    "baseline_pass_rate",
    "cusum_k",
    "cusum_h",
    "kl_threshold_yellow",
    "kl_threshold_red",
    "retest_factor",
    "forbidden_seen"
  ],
  "properties": {
    "baseline_pass_rate": {
      "description": "Reference pass-rate."
    },
    "cusum_k": {
      "description": "CUSUM k parameter (default 0.5)."
    },
    "cusum_h": {
      "description": "CUSUM h threshold (default 4)."
    },
    "kl_threshold_yellow": {
      "description": "0.05."
    },
    "kl_threshold_red": {
      "description": "0.10."
    },
    "retest_factor": {
      "description": "Sample-size multiplier on alert."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
